mapper.select:
select inst.* from ( select id, created_id, created_time, created_timestamp, created_by, modified_time, modified_timestamp, modified_by, version, code, name, biz_number, 0 as status, null as take_time, model_id from flow_instance where deleted = 0 union all select id, created_id, created_time, created_timestamp, created_by, modified_time, modified_timestamp, modified_by, version, code, name, biz_number, status, take_time, model_id from flow_his_instance where deleted = 0 ) inst
inner join ( select distinct fht.instance_id from flow_his_task fht inner join flow_his_task_player fhtp on fht.id = fhtp.task_id and fhtp.deleted = 0 where fht.deleted = 0
and fht.type = 0 and( (fhtp.type = 0 and fhtp.player_id = #{ew.userId})
or( fhtp.type = 1 and fhtp.player_id in
#{roleId}
)
)
and fht.type = 1 and fhtp.player_id = #{ew.userId}
) task_filter on inst.id = task_filter.instance_id
where 1 = 1
and inst.created_id = #{ew.userId}
and inst.name like concat('%', #{ew.name}, '%')
and inst.biz_number = #{ew.bizNumber}
and inst.status = #{ew.status}
order by inst.modified_time desc
